    const find = (i: number): { root: number, parity: number } => {
        if (parent[i] === i) {
            return { root: i, parity: 0 };
        }

        const { root: rootNode, parity: rootParity } = find(parent[i]);

        // Update diff[i]: new diff[i] should be the parity from i to rootNode.
        // Path: i -> parent[i] -> ... -> rootNode
        // Parity(i -> rootNode) = Parity(i -> parent[i]) XOR Parity(parent[i] -> rootNode)
        diff[i] = (diff[i] + rootParity) % 2;

        // Perform path compression
        parent[i] = rootNode;

        return { root: rootNode, parity: diff[i] };
    };

    let addedEdgesCount = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        const rootUResult = find(u);
        const rootVResult = find(v);

        const rootU = rootUResult.root;
        const parityU = rootUResult.parity; // Parity of path u -> rootU

        const rootV = rootVResult.root;
        const parityV = rootVResult.parity; // Parity of path v -> rootV

        // The weight w is 0 or 1.

        if (rootU !== rootV) {
            // Case 1: u and v are in different components. Adding the edge is always safe
            // as it doesn't create a cycle.

            // Merge the components (e.g., attach rootV to rootU).
            parent[rootV] = rootU;

            // We need to set diff[rootV] such that the parity from rootV to rootU is correct.
            // Path: rootV -> v -> u -> rootU
            // Parity(rootV -> rootU) = Parity(rootV -> v) XOR Parity(v -> u) XOR Parity(u -> rootU)
