            // Case 2: u and v are in the same component. Adding the edge creates a cycle.

            // The cycle is formed by: u -> rootU -> v (via existing paths) + edge (v -> u).
            // Path u -> v using existing structure:
            // Path u -> rootU (weight parityU)
            // Path v -> rootV (weight parityV)
            // Since rootU == rootV, the path from u to v is: u -> rootU -> v.
            // The parity of the path u -> v using existing structure is: parityU XOR parityV.

            // The cycle weight parity is: (Path u -> v parity) XOR w
            // Cycle parity = (parityU XOR parityV) XOR w

            const cycleParity = (parityU + parityV + w) % 2;

            // The edge is added if and only if the cycle parity is 0 (even weight).
            if (cycleParity === 0) {
