    const parent: number[] = Array.from({ length: n }, (_, i) => i);

    // parity[i] stores the parity of the weight of the path from i to parent[i].
    // parity[i] = 0 means path weight is even.
    // parity[i] = 1 means path weight is odd.
    const parity: number[] = Array(n).fill(0);

