    const find = (i: number): { root: number, parityToRoot: number } => {
        if (parent[i] === i) {
            return { root: i, parityToRoot: 0 };
        }

        // Recursively find root and parity of parent[i] to root
        const { root: root_i, parityToParentRoot } = find(parent[i]);

        // Update parity[i]: 
        // The new parity[i] is (old parity[i] from i to parent[i]) XOR (parityToParentRoot from parent[i] to root_i)
