            // If they are already in the same component, adding the edge creates a cycle.
            // The condition for addition is that the new cycle's total weight must be even.
            // Cycle weight = Path(u -> v in tree) + w (new edge weight)

            // Parity of Path(u -> v in tree) = Path(u -> rootU) XOR Path(v -> rootU)
            // Path(u -> rootU) parity = this.parity[u]
            // Path(v -> rootU) parity = this.parity[v]
            // Path(u -> v) parity = this.parity[u] ^ this.parity[v]

            // Cycle parity = (this.parity[u] ^ this.parity[v]) ^ w
            const cycleParity = this.parity[u] ^ this.parity[v] ^ w;

            // We only add the edge if the cycle parity is 0 (even).
            if (cycleParity === 0) {
                // Since we are only counting successful additions, and the edge already exists
                // logically in the graph structure (as it connects nodes in the same component),
                // if the cycle is even, we treat it as successfully added in the context of the problem's constraint.
                // However, the problem asks for the number of *added* edges. If it closes a loop, it's not "added" in the DSU sense of merging components.
                // We must check the condition: "if adding it results in all rings having even weight".
                // If cycleParity === 0, the condition is met. We count it.
                return true; 
            } else {
                // Cycle parity is odd. Do not add the edge.
                return false;
            }
        }
    }
}

function solve(n: number, edges: number[][]): number {
    // The key insight is that the condition "every cycle must have an even sum of edge weights"
    // is equivalent to the graph being bipartite IF all weights were 1.
    // Since weights are 0 or 1, this is equivalent to saying that for any two nodes u and v, 
    // the path weight between them must have a well-defined parity, and for any cycle, 
    // the sum of edge weights must be 0 (mod 2). This is precisely what is maintained 
    // by keeping track of path parities using DSU.

    const dsu = new DSU(n);
    let addedEdgesCount = 0;

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2];

        const rootU = dsu.find(u);
        const rootV = dsu.find(v);

        if (rootU !== rootV) {
            // Case 1: Adding the edge connects two different components.
            // This never creates a cycle, so the condition is trivially met. We always add it.
            dsu.union(u, v, w);
            addedEdgesCount++;
        } else {
            // Case 2: Adding the edge creates a cycle.
            // We must check if the cycle formed has an even weight.

            // Path(u -> root) parity is dsu.parity[u].
            // Path(v -> root) parity is dsu.parity[v].

            // Parity of path u -> v in the current tree structure: P_uv = dsu.parity[u] ^ dsu.parity[v].
            // Cycle weight parity = P_uv ^ w (new edge weight).
            const cycleParity = dsu.parity[u] ^ dsu.parity[v] ^ w;

            if (cycleParity === 0) {
                // The cycle is even. We add the edge and count it.
                // Since they are already connected, we don't change the DSU structure, 
                // but we confirm the condition allows this edge to be added.
                addedEdgesCount++;
            } else {
                // The cycle is odd. We reject the edge.
            }
        }
    }

    return addedEdgesCount;
}
